var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"귀여운 꼬마로군.","JPN":"可愛らしい子ではないか。","ENG":"She's a cute kid.","TWN":"真是個可愛的孩子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"귀여운 딸이 저렇게까지 잘 보이려고 애쓰고 있는데 얼굴 한 번 비추지 않은 아빠라니 내 기준에서도 꽤 매정한걸.","JPN":"愛すべき娘が父親の気を引こうと必死に頑張ってるというのに、\\n当の父親は顔一つ見せないとは。\\n私の判断基準からしてもいささか薄情に思えるが。","ENG":"But her dad hasn't shown up yet, even though his adorable daughter is trying so hard to get his attention? That's pretty cold, even by my standards.","TWN":"可愛的女兒為了父親努力成那樣，可是當父親的卻連見都不去見一面，就算是以我的標準，這也太無情了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아니면 법원에서 접근 금지 명령이라도 받은 건가?","JPN":"もしや、裁判所から接近禁止命令でも出されたのかね？","ENG":"Or was he given a restraining order by the court?","TWN":"還是法院下令禁止他靠近嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 부분에 대해서 말인데, 조금 더 자료를 찾아봤습니다.","JPN":"その辺りについてですが、前回に引き続き資料を収集いたしました。","ENG":"I did do some more digging regarding that part.","TWN":"關於那部分，我查了一些資料。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"한소림 양의 모친이 부친과 공식적으로 이혼절차를 밟은 건 맞습니다만......","JPN":"彼女の両親の離婚が正式に成立していることは事実ですが……","ENG":"It is true that Han Sorim's mother and father officially filed for divorce...","TWN":"韓蕭林的母親確實辦理了正式的離婚手續……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"부친은 그 전에 이미 취재 중 이면세계에서 실종된 지 오래라고 하더군요.","JPN":"父親の方は、離婚が成立するよりも遥か以前に、\\n裏世界にて失踪を遂げています。","ENG":"But her father had already gone missing before that while covering a story on the Counterside.","TWN":"但她的父親那之前，就因為取材在異界失蹤很久了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"행정 절차상의 문제로 부친의 사망이 확인되거나 편부모 가정이 아니면 관리국으로부터 소림 양의 양육비를 지원받을 수가 없으니까요. ","JPN":"行政上の都合で、父親の死亡が確認されたか一人親家庭でない限り、\\n管理局から彼女の養育費を支援してもらうことはできません。\\nゆえに母親一人で離婚を進めたわけです。 ","ENG":"As per administrative procedures, Sorim would not have been able to receive any childcare support without confirming her father's death or belonging to a single-parent household. ","TWN":"因為行政程序上的問題，如果不是父親的死亡，或是單親家庭的話，蕭林小姐就無法從管理局獲得撫養費的支援。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런가......","JPN":"そういうことだったか……","ENG":"I see...","TWN":"是嗎……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"병원 기록을 보면 소림 양은 선천적인 근무력증 환자로서 간신히 수저를 드는 정도가 근력의 한계였다고 합니다.","JPN":"病院の記録によれば、彼女は生まれつき筋無力症を患っており、\\n何とかスプーンくらいは持てる程度の筋力しか持っていないとのことです。","ENG":"According to the hospital records, Sorim was born with myasthenia. She could barely lift a spoon by herself.","TWN":"從醫院記錄來看，蕭林小姐作為先天性的肌肉無力症患者，勉強舉起筷子就是她肌肉的極限了。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그런 딸이 받을 충격도 감안해서 단순히 이혼을 해서 아빠를 보지 못한 것으로 알린 모양입니다.","JPN":"彼女の母親はそんな娘にショックを与えることをよしとせず、\\n父親とは離婚したために会えなくなったのだと伝えたそうです。","ENG":"I believe she was told that her father had gone away after the divorce, because her mother didn't want to shock her.","TWN":"考慮到女兒會受到打擊，所以母親才會跟她說見不到爸爸，單純只是因為離婚。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"세상엔 참 안타까운 일들도 많군.","JPN":"世の中、悲しいことが多すぎるな。","ENG":"This world really is full of unfortunate events.","TWN":"世上不幸的事情可真多。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런데 근무력증 환자라더니, 지금은 이제 치료가 된 건가?","JPN":"しかし筋無力症を患っていたということは、今は治ったということなのかね？","ENG":"But is her myasthenia cured now?","TWN":"話說回來，你剛才說她是肌肉無力症患者，那現在已經治好了嗎？"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그럴리가요. 해당 유전자 질환의 치료법은 아직 관리국에서 공개한 기술 중에도 포함되어 있지 않습니다.","JPN":"残念ながらそうではありません。\\nその遺伝子疾患の治療法は、管理局が公開している技術の中にも\\n未だ含まれていないのです。","ENG":"Of course not. This particular genetic disorder does not have any cure, even in the technology revealed by the Administration.","TWN":"怎麼可能。這種遺傳疾病的治療方法，還不存在於管理局公開的技術中。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"적어도 공개한 기술 중에는 말이죠.","JPN":"あくまで公開された技術の中には、ですが。","ENG":"At least, not in the technologies that were revealed.","TWN":"至少在已經公開的技術中還沒有。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"지난번 보고에서는 확답을 못 드렸습니다만......","JPN":"前回の報告では申し上げられませんでしたが……","ENG":"I couldn't give you an answer during the last report...","TWN":"在上次的報告中，我雖然沒有明確的答覆……"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"여러 정황을 종합해 봤을 때 그녀가 가진 카운터 능력, CRF의 대부분은 그녀가 정상적인 생활을 유지하는데 사용되고 있다고 봐도 무방할 것 같습니다.","JPN":"様々な状況を鑑みたところ、彼女が持つカウンター能力、CRFのほとんどは、\\n彼女が正常な生活を維持するために使用されていると\\n結論づけることができます。","ENG":"But taking all accounts in the consideration, I believe it's safe to assume that majority of her CRF, her Counter ability, is being used to maintain her daily life.","TWN":"但根據各種情況，綜合地來看，她所擁有的制裁者能力，CRF幾乎都用在維持正常生活上了。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"일상에서는 100미터 달리기도 완주하지 못할 정도로 최소한의 힘만 사용하고.","JPN":"平時には100メートル走すら完走できないほど最低限の力のみを使用し、","ENG":"She maintains the minimum amount of power in normal circumstances, not even enough to complete a 100m dash.","TWN":"在日常生活中，她連100米衝刺也無法做到，是因為只使用了最低限度的力量吧。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그렇게 아낀 힘을 전투 중에 최대한의 출력으로 발휘하는 거죠.","JPN":"そうやって備蓄した力を戦闘時に最大出力で発揮しています。","ENG":"But then she releases all of her saved powers during battle.","TWN":"然後在戰鬥中，把那份保留下來的力量做最大限度的輸出。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그러니 그녀가 카운터로서의 특별한 능력을 보여주지 못하는 것도 납득이 가는 일입니다.","JPN":"となれば、彼女がカウンターとして特別な能力を示していないことも\\n納得がいきます。","ENG":"That explains why she hasn't shown any special abilities as a Counter.","TWN":"所以，她身為制裁者卻沒有展現特殊能力，這也是可以理解的。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......마이너스와 플러스 요소가 합쳐져 지금은 0이 됐다는 소리로군.","JPN":"マイナスとプラスが合わさって、今は0になってるということか。","ENG":"So her negative and positive factors end up in a zero sum.","TWN":"……也就是說一加一減，最終變成0的意思吧。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이대로라면 앞으로도 고위 카운터로 성장하기는 어렵겠는걸?","JPN":"それでは、今後も高位カウンターへの成長は見込めそうにないな。","ENG":"Then it would be difficult for her to become a high grade Counter.","TWN":"這樣下去，她以後要成長為高等制裁者會很難吧？"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"その通りです。","ENG":"That's right.","TWN":"是的。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 확실히 좋아하는 것에 뛰어난 두각을 보이고 있는 만큼.","JPN":"しかし、自身が好きなことに関しては、確実に頭角を現しているのです。","ENG":"But she still shows incredible prominence in her areas of interest.","TWN":"不過在喜歡的事物上，她確實展現了很高的天賦。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어떤 방법으로든 그녀가 선천적인 근무력증을 치료할 수 있게 된다면......","JPN":"いかなる方法であれ、彼女の先天的な筋無力症を\\n治療することさえできれば……","ENG":"If we are somehow able to cure her innate myasthenia...","TWN":"只要能用某種方法，將她的肌肉無力症治好……"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그때는 꽤 큰 기대를 걸어봐도 되지 않을까 싶네요.","JPN":"そのときは、大いに期待してよいのではないでしょうか。","ENG":"We could expect great things from her.","TWN":"到時候應該可以期待一下吧。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};